import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;

public class BankingApp extends AppCompatActivity {

    private TextView accountBalance;
    private EditText transactionAmount;
    private Button processTransaction;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking_app);

        accountBalance = findViewById(R.id.account_balance);
        transactionAmount = findViewById(R.id.transaction_amount);
        processTransaction = findViewById(R.id.process_transaction);

        processTransaction.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction();
            }
        });
    }

    private void processTransaction() {
        double amount = Double.parseDouble(transactionAmount.getText().toString());
        double currentBalance = Double.parseDouble(accountBalance.getText().toString());

        if (amount > currentBalance) {
            // Display error message
            return;
        }

        // Update account balance
        currentBalance -= amount;
        accountBalance.setText(String.valueOf(currentBalance));

        // Display success message
    }
}